mapper.select:
select count(*)
from nx_customer_user_referral r
where r.source_owner_type = 'CUSTOMER_USER'
  and r.source_owner_id = #{sourceOwnerId}
  and r.qualification_status = 'QUALIFIED'
  and r.nx_customer_user_referral_id > #{lastReadReferralId}
  and r.bind_time >= #{displaySince}

select count(*) from nx_customer_user_referral
where source_owner_type = 'EXTERNAL_PROMOTER'
  and source_owner_id = #{promoterId}

select count(*) from nx_customer_user_referral
where source_owner_type = #{sourceOwnerType}
  and source_owner_id = #{sourceOwnerId}
  and qualification_status = 'QUALIFIED'

select count(*) from nx_customer_user_referral
where source_owner_type = #{sourceOwnerType}
  and source_owner_id = #{sourceOwnerId}

mapper.delete:
delete from nx_customer_user_referral
where source_owner_type = #{sourceOwnerType}
  and source_owner_id = #{sourceOwnerId}

delete from nx_customer_user_referral
where (source_owner_type = #{sourceOwnerType} and source_owner_id = #{sourceOwnerId})
   or promoter_id = #{sourceOwnerId}
